st.title("🌱 당신을 위한 깊은 위로, 50가지 마음 처방전")
user_input = st.text_input("지금 어떤 기분이 드시나요? (예: 죽고싶어, 너무 슬퍼, 화나네...)")

if user_input:
    found = False
    for category, data in emotion_data.items():
        if any(key in user_input for key in data["keywords"]):
            st.subheader(f"💡 [{category}] 마음을 위한 다정한 위로")
            st.markdown(f"**{data['공감']}**")
            st.write("---")
            st.write("### 🧘 당신을 위한 정성스러운 처방:")
            for i, action in enumerate(data["처방"], 1):
                st.write(f"{i}. {action}")
            found = True
            break
    
    if not found:
        st.write("당신의 마음을 더 자세히 알고 싶어요. 지금 어떤 일을 겪고 계신가요? 혹은 마음속에 어떤 말들이 맴돌고 있나요?")
